// AccountPage.jsx
import { useState } from "react";
import "./AccountPage.css";

const SECTIONS = [
  {
    id: "profile",
    label: "My Profile",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      >
        <circle cx="12" cy="8" r="4" />
        <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
      </svg>
    ),
  },
  {
    id: "orders",
    label: "My Orders",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      >
        <rect x="3" y="3" width="18" height="18" rx="2" />
        <path d="M8 7h8M8 12h8M8 17h5" />
      </svg>
    ),
  },
  {
    id: "address",
    label: "Saved Addresses",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      >
        <path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7z" />
        <circle cx="12" cy="9" r="2.5" />
      </svg>
    ),
  },
  {
    id: "wishlist",
    label: "Wishlist",
    icon: (
      <svg
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
      >
        <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
      </svg>
    ),
  },
];

const ORDERS = [
  {
    id: "#TG-20419",
    date: "2 Apr 2026",
    items: 3,
    products: "Floral Wrap Dress, White Linen Blazer, Strappy Heels",
    total: "₹5,299",
    status: "shipped",
    statusLabel: "Shipped",
  },
  {
    id: "#TG-20311",
    date: "18 Mar 2026",
    items: 2,
    products: "Slim Fit Jeans, Cotton Crop Top",
    total: "₹2,150",
    status: "delivered",
    statusLabel: "Delivered",
  },
  {
    id: "#TG-20198",
    date: "5 Mar 2026",
    items: 1,
    products: "Leather Tote Bag – Tan Brown",
    total: "₹3,899",
    status: "processing",
    statusLabel: "Processing",
  },
  {
    id: "#TG-20044",
    date: "12 Feb 2026",
    items: 4,
    products: "Summer Co-ord Set, Earrings, Sunglasses, Hair Clip",
    total: "₹4,680",
    status: "delivered",
    statusLabel: "Delivered",
  },
];

const ORDER_FILTERS = ["All", "Processing", "Shipped", "Delivered"];

// ── Navbar ──────────────────────────────────────────────────────────────────

function Navbar() {
  return (
    <nav className="navbar">
      <div className="navbar-logo">TECYGIG</div>
      <div className="navbar-links">
        <span className="active">Women</span>
        <span>Men</span>
        <span>Kids</span>
        <span>Home</span>
        <span>All Brands</span>
      </div>
      <div className="navbar-right">My Account</div>
    </nav>
  );
}

// ── Sidebar ──────────────────────────────────────────────────────────────────

function Sidebar({ active, onSelect, onSignOut }) {
  return (
    <aside className="sidebar">
      <div className="user-avatar">SR</div>
      <div className="user-name">Sneha Rao</div>
      <div className="user-email">sneha.rao@gmail.com</div>
      <div className="user-badge">
        <span className="badge">Premium Member</span>
      </div>
      <hr className="sidebar-divider" />
      <ul className="sidebar-menu">
        {SECTIONS.map((s) => (
          <li
            key={s.id}
            className={active === s.id ? "active" : ""}
            onClick={() => onSelect(s.id)}
          >
            {s.icon}
            {s.label}
          </li>
        ))}
      </ul>
      <button className="signout-btn" onClick={onSignOut}>
        <svg
          width="15"
          height="15"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
        >
          <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" />
          <polyline points="16 17 21 12 16 7" />
          <line x1="21" y1="12" x2="9" y2="12" />
        </svg>
        Sign Out
      </button>
    </aside>
  );
}

// ── Profile Section ───────────────────────────────────────────────────────────

function ProfileSection() {
  const [form, setForm] = useState({
    firstName: "Sneha",
    lastName: "Rao",
    email: "sneha.rao@gmail.com",
    phone: "+91 98765 43210",
    gender: "Female",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  return (
    <div className="content-card">
      <div className="section-header">
        <div className="section-title">Personal Information</div>
        <div className="section-subtitle">
          Update your profile details below
        </div>
      </div>
      <div className="info-grid">
        <div className="info-field">
          <label>First Name</label>
          <input
            name="firstName"
            value={form.firstName}
            onChange={handleChange}
          />
        </div>
        <div className="info-field">
          <label>Last Name</label>
          <input
            name="lastName"
            value={form.lastName}
            onChange={handleChange}
          />
        </div>
        <div className="info-field">
          <label>Email Address</label>
          <input name="email" value={form.email} onChange={handleChange} />
        </div>
        <div className="info-field">
          <label>Phone Number</label>
          <input name="phone" value={form.phone} onChange={handleChange} />
        </div>
        <div className="info-field">
          <label>Gender</label>
          <input name="gender" value={form.gender} onChange={handleChange} />
        </div>
      </div>
      <button className="save-btn">Save Changes</button>
    </div>
  );
}

// ── Orders Section ────────────────────────────────────────────────────────────

function OrdersSection() {
  const [activeFilter, setActiveFilter] = useState("All");

  const filtered =
    activeFilter === "All"
      ? ORDERS
      : ORDERS.filter((o) => o.statusLabel === activeFilter);

  return (
    <div className="content-card">
      <div className="section-header">
        <div className="section-title">Order History</div>
        <div className="section-subtitle">Track and manage all your orders</div>
      </div>

      <div className="stats-row">
        <div className="stat-card">
          <div className="stat-num">12</div>
          <div className="stat-label">Total Orders</div>
        </div>
        <div className="stat-card">
          <div className="stat-num">9</div>
          <div className="stat-label">Delivered</div>
        </div>
        <div className="stat-card">
          <div className="stat-num">₹24,850</div>
          <div className="stat-label">Total Spent</div>
        </div>
      </div>

      <div className="filter-tabs">
        {ORDER_FILTERS.map((f) => (
          <button
            key={f}
            className={`tab-btn ${activeFilter === f ? "active" : ""}`}
            onClick={() => setActiveFilter(f)}
          >
            {f}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">📦</div>
          <p>No orders found in this category.</p>
        </div>
      ) : (
        filtered.map((order) => (
          <div className="order-item" key={order.id}>
            <div className="order-header">
              <div>
                <div className="order-id">{order.id}</div>
                <div className="order-date">
                  {order.date} · {order.items} item{order.items > 1 ? "s" : ""}
                </div>
              </div>
              <span className={`status-pill ${order.status}`}>
                {order.statusLabel}
              </span>
            </div>
            <div className="order-products">{order.products}</div>
            <div className="order-footer">
              <span className="order-total">{order.total}</span>
              <button className="track-btn">
                {order.status === "delivered" ? "View Details" : "Track Order"}
              </button>
            </div>
          </div>
        ))
      )}
    </div>
  );
}

// ── Address Section ───────────────────────────────────────────────────────────

function AddressSection() {
  return (
    <div className="content-card">
      <div className="section-header">
        <div className="section-title">Saved Addresses</div>
        <div className="section-subtitle">Manage your delivery addresses</div>
      </div>
      <div className="empty-state">
        <div className="empty-state-icon">📍</div>
        <p>No addresses saved yet. Add one to speed up checkout!</p>
        <button className="save-btn">+ Add New Address</button>
      </div>
    </div>
  );
}

// ── Wishlist Section ──────────────────────────────────────────────────────────

function WishlistSection() {
  return (
    <div className="content-card">
      <div className="section-header">
        <div className="section-title">Wishlist</div>
        <div className="section-subtitle">Items you've saved for later</div>
      </div>
      <div className="empty-state">
        <div className="empty-state-icon">🤍</div>
        <p>Your wishlist is empty. Start saving your favourite items!</p>
        <button className="save-btn">Browse Products</button>
      </div>
    </div>
  );
}

// ── Root Component ────────────────────────────────────────────────────────────

export default function AccountPage() {
  const [activeSection, setActiveSection] = useState("profile");

  const handleSignOut = () => {
    alert("You have been signed out.");
  };

  const renderSection = () => {
    switch (activeSection) {
      case "profile":
        return <ProfileSection />;
      case "orders":
        return <OrdersSection />;
      case "address":
        return <AddressSection />;
      case "wishlist":
        return <WishlistSection />;
      default:
        return <ProfileSection />;
    }
  };

  return (
    <>
      <Navbar />
      <div className="account-page">
        <Sidebar
          active={activeSection}
          onSelect={setActiveSection}
          onSignOut={handleSignOut}
        />
        <main>{renderSection()}</main>
      </div>
    </>
  );
}
